import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Product } from '../../core/models';

/** Product detail. Edit is gated to admin. service_agent wires ApiService.getProduct(id). */
@Component({
  selector: 'app-product-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './product-detail.component.html',
  styleUrl: './product-detail.component.css',
})
export class ProductDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly product = signal<Product | null>({
    id: 'p1',
    sku: 'WID-001',
    name: 'Widget',
    costCents: 450,
    priceCents: 999,
    onHand: 120,
  });

  readonly canEdit = computed(() => this.auth.isAdmin());
  id = '';

  constructor(public auth: AuthService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.id = this.route.snapshot.paramMap.get('id') ?? '';
    // service_agent: this.product.set(await ApiService.getProduct(this.id)).
  }

  money(cents: number): string {
    return (cents / 100).toLocaleString(undefined, { style: 'currency', currency: 'USD' });
  }
}
